  }
});

// ─── 404 Handler ───────────────────────────────────────────────────────────────

app.use((_req: Request, res: Response) => {
  res.status(404).json({
    success: false,
    message: '请求的资源不存在',
  });
});

// ─── Global Error Handler ──────────────────────────────────────────────────────

app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('❌ Server Error:', err);

  if (err.name === 'SequelizeValidationError') {
    return res.status(400).json({
      success: false,
      message: '数据验证失败',
      errors: err,
    });
  }

  if (err.name === 'SequelizeUniqueConstraintError') {
    return res.status(409).json({
      success: false,
      message: '数据已存在，请勿重复提交',
    });
  }

  res.status(500).json({
    success: false,
    message: process.env.NODE_ENV === 'production' ? '服务器内部错误' : err.message,
  });
});

// ─── Start Server ──────────────────────────────────────────────────────────────

async function startServer(): Promise<void> {
  try {
    // Initialize database connection and sync models
    await initializeDatabase();

    app.listen(PORT, () => {
      console.log(`🚀 E-commerce API Server is running at http://localhost:${PORT}`);
      console.log(`📦 Environment: ${process.env.NODE_ENV || 'development'}`);
      console.log(`🔗 Health check: http://localhost:${PORT}/api/health`);
    });
  } catch (error) {
    console.error('❌ Failed to start server:', error);
    process.exit(1);
  }
}

startServer();

export default app;

import { Router, Request, Response, NextFunction } from 'express';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { pool } from '../db';
import { authenticateToken, optionalAuth } from '../middleware/auth';
import type { User, AuthPayload, ApiResponse } from '../types';

const router = Router();

const JWT_SECRET = process.env.JWT_SECRET || 'ecommerce-platform-secret-key';
const JWT_EXPIRES_IN = process.env.JWT_EXPIRES_IN || '24h';
const SALT_ROUNDS = 12;

// ─── Helper: Generate JWT ────────────────────────────────────────────────────

function generateToken(payload: AuthPayload): string {
  return jwt.sign(payload as object, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN });
}

// ─── Helper: Sanitize User Response ──────────────────────────────────────────

function sanitizeUser(user: User): Omit<User, 'password_hash'> {
  const { password_hash, ...safeUser } = user as User & { password_hash: string };
  return safeUser;
}

// ─── POST /register ──────────────────────────────────────────────────────────

router.post('/register', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password, name, phone } = req.body;

    // Validate required fields
    if (!email || !password || !name) {
      return res.status(400).json({
        success: false,
        error: 'Missing required fields: email, password, name',
      } as ApiResponse<null>);
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid email format',
      } as ApiResponse<null>);
    }

    // Validate password strength
    if (password.length < 8) {
      return res.status(400).json({
        success: false,
        error: 'Password must be at least 8 characters long',
      } as ApiResponse<null>);
    }

    // Check if user already exists
    const existingUser = await pool.query(
      'SELECT id FROM users WHERE email = $1',
      [email.toLowerCase().trim()]
    );

    if (existingUser.rows.length > 0) {
      return res.status(409).json({
        success: false,
        error: 'A user with this email already exists',
      } as ApiResponse<null>);
    }

    // Hash password
    const password_hash = await bcrypt.hash(password, SALT_ROUNDS);

    // Insert new user
    const result = await pool.query(
      `INSERT INTO users (email, password_hash, name, phone, role)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING id, email, name, phone, role, created_at, updated_at`,
      [email.toLowerCase().trim(), password_hash, name.trim(), phone || null, 'customer']
    );

    const user: User = result.rows[0];

    // Generate token
    const token = generateToken({ sub: user.id, email: user.email, role: user.role });

    return res.status(201).json({
      success: true,
      data: {
        user: sanitizeUser(user),
        token,
      },
    } as ApiResponse<{ user: Omit<User, 'password_hash'>; token: string }>);
  } catch (error) {
    next(error);
  }
});

// ─── POST /login ─────────────────────────────────────────────────────────────

router.post('/login', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({
        success: false,
        error: 'Email and password are required',
      } as ApiResponse<null>);
    }

    // Find user by email
    const result = await pool.query(
      'SELECT id, email, password_hash, name, phone, role, created_at, updated_at FROM users WHERE email = $1',
      [email.toLowerCase().trim()]
    );

    if (result.rows.length === 0) {
      return res.status(401).json({
        success: false,
        error: 'Invalid email or password',
      } as ApiResponse<null>);
    }

    const user = result.rows[0];

    // Verify password
    const isPasswordValid = await bcrypt.compare(password, user.password_hash);
    if (!isPasswordValid) {
      return res.status(401).json({
        success: false,
        error: 'Invalid email or password',
      } as ApiResponse<null>);
    }

    // Check if user is active
    if (user.is_active === false) {
      return res.status(403).json({
        success: false,
        error: 'Account is deactivated. Please contact support.',
      } as ApiResponse<null>);
    }

    // Update last login timestamp
    await pool.query('UPDATE users SET last_login_at = NOW() WHERE id = $1', [user.id]);

    // Generate token
    const token = generateToken({ sub: user.id, email: user.email, role: user.role });

    return res.status(200).json({
      success: true,
      data: {
        user: sanitizeUser(user),
        token,
      },
    } as ApiResponse<{ user: Omit<User, 'password_hash'>; token: string }>);
  } catch (error) {
    next(error);
  }
});

