import { Router, Request, Response, NextFunction } from 'express';
import { pool } from '../db';
import { authenticateToken, requireAdmin } from '../middleware/auth';
import type { Product, ApiResponse, PaginatedResponse } from '../types';

const router = Router();

// ─── GET / — List Products (paginated, filterable, sortable) ─────────────────

router.get('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const {
      page = '1',
      limit = '20',
      sort = 'created_at',
      order = 'DESC',
      category,
      search,
      min_price,
      max_price,
      in_stock,
    } = req.query;

    const pageNum = Math.max(1, parseInt(page as string, 10) || 1);
    const limitNum = Math.min(100, Math.max(1, parseInt(limit as string, 10) || 20));
    const offset = (pageNum - 1) * limitNum;

    // Build WHERE clause dynamically
    const conditions: string[] = ['p.is_deleted = FALSE'];
    const values: any[] = [];
    let paramIndex = 1;

    if (category) {
      conditions.push(`p.category = $${paramIndex++}`);
      values.push(category);
    }

    if (search) {
      conditions.push(
        `(p.name ILIKE $${paramIndex} OR p.description ILIKE $${paramIndex})`
      );
      values.push(`%${search}%`);
      paramIndex++;
    }

    if (min_price) {
      conditions.push(`p.price >= $${paramIndex++}`);
      values.push(parseFloat(min_price as string));
    }

    if (max_price) {
      conditions.push(`p.price <= $${paramIndex++}`);
      values.push(parseFloat(max_price as string));
    }

    if (in_stock === 'true') {
      conditions.push('p.stock_quantity > 0');
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    // Validate sort column to prevent SQL injection
    const allowedSortColumns = ['name', 'price', 'stock_quantity', 'created_at', 'updated_at', 'category'];
    const sortColumn = allowedSortColumns.includes(sort as string) ? sort : 'created_at';
    const sortOrder = (order as string).toUpperCase() === 'ASC' ? 'ASC' : 'DESC';

    // Count total records
    const countResult = await pool.query(
      `SELECT COUNT(*) FROM products p ${whereClause}`,
      values
    );
    const total = parseInt(countResult.rows[0].count, 10);

    // Fetch paginated products
    const productsResult = await pool.query(
      `SELECT p.id, p.name, p.description, p.price, p.compare_at_price,
              p.category, p.image_url, p.stock_quantity, p.sku, p.is_active,
              p.created_at, p.updated_at
       FROM products p
       ${whereClause}
       ORDER BY p.${sortColumn} ${sortOrder}
       LIMIT $${paramIndex++} OFFSET $${paramIndex++}`,
      [...values, limitNum, offset]
    );

    return res.status(200).json({
      success: true,
      data: productsResult.rows,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages: Math.ceil(total / limitNum),
      },
    } as ApiResponse<Product[]> & { pagination: PaginatedResponse });
  } catch (error) {
    next(error);
  }
});

