// ─── POST / — Create product (Admin only) ────────────────────────────────────

router.post('/', authenticateToken, requireAdmin, async (req: Request, res: Response, next: NextFunction) => {
  try {
    const {
      name,
      description,
      price,
      compare_at_price,
      category,
      image_url,
      images,
      stock_quantity,
      sku,
    } = req.body;

    // Validate required fields
    if (!name || price === undefined || stock_quantity === undefined) {
      return res.status(400).json({
        success: false,
        error: 'Missing required fields: name, price, stock_quantity',
      } as ApiResponse<null>);
    }

    if (price < 0) {
      return res.status(400).json({
        success: false,
        error: 'Price must be a non-negative number',
      } as ApiResponse<null>);
    }

    if (stock_quantity < 0 || !Number.isInteger(stock_quantity)) {
      return res.status(400).json({
        success: false,
        error: 'Stock quantity must be a non-negative integer',
      } as ApiResponse<null>);
    }

    // Check SKU uniqueness if provided
    if (sku) {
      const existingSku = await pool.query('SELECT id FROM products WHERE sku = $1 AND is_deleted = FALSE', [sku]);
      if (existingSku.rows.length > 0) {
        return res.status(409).json({
          success: false,
          error: 'A product with this SKU already exists',
        } as ApiResponse<null>);
      }
    }

    const result = await pool.query(
      `INSERT INTO products (name, description, price, compare_at_price, category, image_url, images, stock_quantity, sku)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
       RETURNING id, name, description, price, compare_at_price, category, image_url, images, stock_quantity, sku, is_active, created_at, updated_at`,
      [
        name.trim(),
        description || null,
        price,
        compare_at_price || null,
        category || null,
        image_url || null,
        images ? JSON.stringify(images) : null,
        stock_quantity,
        sku || null,
      ]
    );

    return res.status(201).json({
      success: true,
      data: result.rows[0],
    } as ApiResponse<Product>);
  } catch (error) {
    next(error);
  }
});

// ─── PUT /:id — Update product (Admin only) ──────────────────────────────────

router.put('/:id', authenticateToken, requireAdmin, async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { id } = req.params;
    const {
      name,
      description,
      price,
      compare_at_price,
      category,
      image_url,
      images,
      stock_quantity,
      sku,
      is_active,
    } = req.body;

    // Check product exists
    const existingProduct = await pool.query(
      'SELECT id FROM products WHERE id = $1 AND is_deleted = FALSE',
      [id]
    );

    if (existingProduct.rows.length === 0) {
      return res.status(404).json({
        success: false,
        error: 'Product not found',
      } as ApiResponse<null>);
    }

    // Check SKU uniqueness if changing
    if (sku) {
      const existingSku = await pool.query(
        'SELECT id FROM products WHERE sku = $1 AND id != $2 AND is_deleted = FALSE',
        [sku, id]
      );
      if (existingSku.rows.length > 0) {
        return res.status(409).json({
          success: false,
          error: 'Another product with this SKU already exists',
        } as ApiResponse<null>);
      }
    }

    // Build dynamic update
    const updates: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    const fields: Record<string, any> = {
      name, description, price, compare_at_price, category,
      image_url, stock_quantity, sku, is_active,
    };

    for (const [key, value] of Object.entries(fields)) {
      if (value !== undefined) {
        if (key === 'price' && value < 0) {
          return res.status(400).json({
            success: false,
            error: 'Price must be a non-negative number',
          } as ApiResponse<null>);
        }
        if (key === 'stock_quantity' && (value < 0 || !Number.isInteger(value))) {
          return res.status(400).json({
            success: false,
            error: 'Stock quantity must be a non-negative integer',
          } as ApiResponse<null>);
        }
        updates.push(`${key} = $${paramIndex++}`);
        values.push(value);
      }
    }

    if (images !== undefined) {
      updates.push(`images = $${paramIndex++}`);
      values.push(JSON.stringify(images));
    }

    if (updates.length === 0) {
      return res.status(400).json({
        success: false,
        error: 'No valid fields to update',
      } as ApiResponse<null>);
    }

    updates.push(`updated_at = NOW()`);
    values.push(id);

    const result = await pool.query(
      `UPDATE products SET ${updates.join(', ')} WHERE id = $${paramIndex}
       RETURNING id, name, description, price, compare_at_price, category, image_url, images, stock_quantity, sku, is_active, created_at, updated_at`,
      values
    );

    return res.status(200).json({
      success: true,
      data: result.rows[0],
    } as ApiResponse<Product>);
  } catch (error) {
    next(error);
  }
});

// ─── DELETE /:id — Soft-delete product (Admin only) ──────────────────────────

router.delete('/:id', authenticateToken, requireAdmin, async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { id } = req.params;

    const result = await pool.query(
      `UPDATE products SET is_deleted = TRUE, updated_at = NOW() WHERE id = $1 AND is_deleted = FALSE RETURNING id`,
      [id]
