import { Router, Request, Response, NextFunction } from 'express';
import { pool } from '../db';
import { authenticateToken } from '../middleware/auth';
import type { CartItem, Product, ApiResponse } from '../types';

const router = Router();

// All cart routes require authentication
router.use(authenticateToken);

// ─── Helper: Get or create cart for user ──────────────────────────────────────

async function getOrCreateCart(userId: string): Promise<string> {
  let result = await pool.query(
    'SELECT id FROM carts WHERE user_id = $1 AND is_active = TRUE',
    [userId]
  );

  if (result.rows.length === 0) {
    result = await pool.query(
      'INSERT INTO carts (user_id) VALUES ($1) RETURNING id',
      [userId]
    );
  }

  return result.rows[0].id;
}

// ─── Helper: Calculate cart totals ────────────────────────────────────────────

async function getCartWithItems(cartId: string) {
  const result = await pool.query(
    `SELECT ci.id, ci.cart_id, ci.product_id, ci.quantity,
            p.name AS product_name, p.price AS unit_price, p.image_url AS product_image,
            p.stock_quantity, p.is_active AS product_active, p.is_deleted AS product_deleted
     FROM cart_items ci
     JOIN products p ON ci.product_id = p.id
     WHERE ci.cart_id = $1 AND ci.is_active = TRUE
     ORDER BY ci.created_at DESC`,
    [cartId]
  );

  const items = result.rows.map((row) => ({
    id: row.id,
    cart_id: row.cart_id,
    product_id: row.product_id,
    quantity: row.quantity,
    product_name: row.product_name,
    unit_price: parseFloat(row.unit_price),
    product_image: row.product_image,
    stock_quantity: row.stock_quantity,
    product_active: row.product_active,
    product_deleted: row.product_deleted,
    subtotal: parseFloat(row.unit_price) * row.quantity,
    available: row.product_active && !row.product_deleted && row.stock_quantity > 0,
  }));

  const subtotal = items.reduce((sum: number, item: any) => sum + item.subtotal, 0);
  const itemCount = items.reduce((sum: number, item: any) => sum + item.quantity, 0);

  return {
    cart_id: cartId,
    items,
    item_count: itemCount,
    subtotal: Math.round(subtotal * 100) / 100,
  };
}

// ─── GET / — Retrieve user's cart ────────────────────────────────────────────

router.get('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const cartId = await getOrCreateCart(userId);
    const cart = await getCartWithItems(cartId);

    return res.status(200).json({
      success: true,
      data: cart,
    } as ApiResponse<typeof cart>);
  } catch (error) {
    next(error);
  }
});

// ─── POST /items — Add item to cart ──────────────────────────────────────────

router.post('/items', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const { product_id, quantity = 1 } = req.body;

    if (!product_id) {
      return res.status(400).json({
        success: false,
        error: 'product_id is required',
      } as ApiResponse<null>);
    }

    if (!Number.isInteger(quantity) || quantity < 1) {
      return res.status(400).json({
        success: false,
        error: 'Quantity must be a positive integer',
      } as ApiResponse<null>);
    }

    // Verify product exists and is available
    const productResult = await pool.query(
      'SELECT id, name, price, stock_quantity, is_active, is_deleted FROM products WHERE id = $1',
      [product_id]
    );

    if (productResult.rows.length === 0 || productResult.rows[0].is_deleted) {
      return res.status(404).json({
        success: false,
        error: 'Product not found',
      } as ApiResponse<null>);
    }

    const product = productResult.rows[0];

    if (!product.is_active) {
      return res.status(400).json({
        success: false,
        error: 'Product is currently unavailable',
      } as ApiResponse<null>);
    }

    // Get or create cart
    const cartId = await getOrCreateCart(userId);

    // Check if product already in cart
    const existingItem = await pool.query(
      'SELECT id, quantity FROM cart_items WHERE cart_id = $1 AND product_id = $2 AND is_active = TRUE',
      [cartId, product_id]
    );

    if (existingItem.rows.length > 0) {
      // Update quantity
      const newQuantity = existingItem.rows[0].quantity + quantity;

      if (newQuantity > product.stock_quantity) {
        return res.status(400).json({
          success: false,
          error: `Insufficient stock. Only ${product.stock_quantity} available.`,
        } as ApiResponse<null>);
      }

      await pool.query(
        'UPDATE cart_items SET quantity = $1, updated_at = NOW() WHERE id = $2',
        [newQuantity, existingItem.rows[0].id]
      );
    } else {
      // Check stock
      if (quantity > product.stock_quantity) {
        return res.status(400).json({
          success: false,
          error: `Insufficient stock. Only ${product.stock_quantity} available.`,
        } as ApiResponse<null>);
      }

      // Add new item
      await pool.query(
        'INSERT INTO cart_items (cart_id, product_id, quantity) VALUES ($1, $2, $3)',
        [cartId, product_id, quantity]
      );
    }

    // Return updated cart
    const cart = await getCartWithItems(cartId);

    return res.status(200).json({
      success: true,
      data: cart,
    } as ApiResponse<typeof cart>);
  } catch (error) {
    next(error);
  }
});

// ─── PUT /items/:itemId — Update cart item quantity ──────────────────────────

router.put('/items/:itemId', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const { itemId } = req.params;
    const { quantity } = req.body;

    if (quantity === undefined || !Number.isInteger(quantity) || quantity < 0) {
      return res.status(400).json({
        success: false,
        error: 'Quantity must be a non-negative integer',
      } as ApiResponse<null>);
    }

    // Get cart
    const cartResult = await pool.query(
      'SELECT id FROM carts WHERE user_id = $1 AND is_active = TRUE',
      [userId]
    );

    if (cartResult.rows.length === 0) {
      return res.status(404).json({ success: false, error: 'Cart not found' } as ApiResponse<null>);
    }

    const cartId = cartResult.rows[0].id;

    // Verify item belongs to this cart
    const itemResult = await pool.query(
      `SELECT ci.id, ci.quantity, p.stock_quantity
       FROM cart_items ci
       JOIN products p ON ci.product_id = p.id
       WHERE ci.id = $1 AND ci.cart_id = $2 AND ci.is_active = TRUE`,
      [itemId, cartId]
    );

    if (itemResult.rows.length === 0) {
      return res.status(404).json({ success: false, error: 'Cart item not found' } as ApiResponse<null>);
    }

    if (quantity === 0) {
      // Remove item
      await pool.query(
        'UPDATE cart_items SET is_active = FALSE, updated_at = NOW() WHERE id = $1',
        [itemId]
      );
    } else {
      // Check stock
      if (quantity > itemResult.rows[0].stock_quantity) {
        return res.status(400).json({
          success: false,
          error: `Insufficient stock. Only ${itemResult.rows[0].stock_quantity} available.`,
        } as ApiResponse<null>);
      }

      await pool.query(
        'UPDATE cart_items SET quantity = $1, updated_at = NOW() WHERE id = $2',
        [quantity, itemId]
      );
    }

    const cart = await getCartWithItems(cartId);

    return res.status(200).json({
      success: true,
      data: cart,
    } as ApiResponse<typeof cart>);
  } catch (error) {
    next(error);
  }
});

// ─── DELETE /items/:itemId — Remove item from cart ───────────────────────────

router.delete('/items/:itemId', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const { itemId } = req.params;

    const cartResult = await pool.query(
      'SELECT id FROM carts WHERE user_id = $1 AND is_active = TRUE',
      [userId]
    );

    if (cartResult.rows.length === 0) {
      return res.status(404).json({ success: false, error: 'Cart not found' } as ApiResponse<null>);
    }

    const cartId = cartResult.rows[0].id;

    const result = await pool.query(
      'UPDATE cart_items SET is_active = FALSE, updated_at = NOW() WHERE id = $1 AND cart_id = $2 AND is_active = TRUE RETURNING id',
      [itemId, cartId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ success: false, error: 'Cart item not found' } as ApiResponse<null>);
    }

    const cart = await getCartWithItems(cartId);

    return res.status(200).json({
      success: true,
      data: cart,
    } as ApiResponse<typeof cart>);
  } catch (error) {
    next(error);
  }
});

// ─── DELETE / — Clear entire cart ────────────────────────────────────────────

router.delete('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;

    const cartResult = await pool.query(
      'SELECT id FROM carts WHERE user_id = $1 AND is_active = TRUE',
      [userId]
    );

    if (cartResult.rows.length === 0) {
      return res.status(200).json({
        success: true,
        data: { message: 'Cart is already empty', items: [], item_count: 0, subtotal: 0 },
      } as ApiResponse<any>);
    }

    const cartId = cartResult.rows[0].id;

    await pool.query(
      'UPDATE cart_items SET is_active = FALSE, updated_at = NOW() WHERE cart_id = $1 AND is_active = TRUE',
      [cartId]
    );

    return res.status(200).json({
      success: true,
      data: { cart_id: cartId, items: [], item_count: 0, subtotal: 0 },
    } as ApiResponse<any>);
