import { Router, Request, Response, NextFunction } from 'express';
import { pool } from '../db';
import { authenticateToken, requireAdmin } from '../middleware/auth';
import type { Order, OrderItem, ApiResponse, PaginatedResponse } from '../types';

const router = Router();

// All order routes require authentication
router.use(authenticateToken);

// ─── Helper: Generate order number ────────────────────────────────────────────

function generateOrderNumber(): string {
  const timestamp = Date.now().toString(36).toUpperCase();
  const random = Math.random().toString(36).substring(2, 6).toUpperCase();
  return `ORD-${timestamp}-${random}`;
}

// ─── Helper: Validate cart and check stock ────────────────────────────────────

async function validateCartForCheckout(cartId: string, userId: string) {
  const items = await pool.query(
    `SELECT ci.id AS cart_item_id, ci.product_id, ci.quantity,
            p.name AS product_name, p.price, p.stock_quantity, p.is_active, p.is_deleted
     FROM cart_items ci
     JOIN products p ON ci.product_id = p.id
     WHERE ci.cart_id = $1 AND ci.is_active = TRUE`,
    [cartId]
  );

  if (items.rows.length === 0) {
    throw { status: 400, message: 'Cart is empty' };
  }

  const errors: string[] = [];
  const validItems: any[] = [];

  for (const item of items.rows) {
    if (item.is_deleted) {
      errors.push(`Product "${item.product_name}" is no longer available`);
      continue;
    }
    if (!item.is_active) {
      errors.push(`Product "${item.product_name}" is currently unavailable`);
      continue;
    }
    if (item.stock_quantity < item.quantity) {
      errors.push(
        `Insufficient stock for "${item.product_name}". Requested: ${item.quantity}, Available: ${item.stock_quantity}`
      );
      continue;
    }
    validItems.push(item);
  }

  if (errors.length > 0) {
    throw { status: 400, message: errors.join('; ') };
  }

  return validItems;
}

// ─── GET / — List user orders ────────────────────────────────────────────────

router.get('/', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const userRole = (req as any).user?.role;
    const {
      page = '1',
      limit = '20',
      status,
      sort = 'created_at',
      order = 'DESC',
    } = req.query;

    const pageNum = Math.max(1, parseInt(page as string, 10) || 1);
    const limitNum = Math.min(100, Math.max(1, parseInt(limit as string, 10) || 20));
    const offset = (pageNum - 1) * limitNum;

    const conditions: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    // Non-admin users can only see their own orders
    if (userRole !== 'admin') {
      conditions.push(`o.user_id = $${paramIndex++}`);
      values.push(userId);
    }

    if (status) {
      conditions.push(`o.status = $${paramIndex++}`);
      values.push(status);
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    const allowedSortColumns = ['created_at', 'updated_at', 'total_amount', 'status'];
    const sortColumn = allowedSortColumns.includes(sort as string) ? sort : 'created_at';
    const sortOrder = (order as string).toUpperCase() === 'ASC' ? 'ASC' : 'DESC';

    // Count
    const countResult = await pool.query(
      `SELECT COUNT(*) FROM orders o ${whereClause}`,
      values
    );
    const total = parseInt(countResult.rows[0].count, 10);

    // Fetch orders with item count
    const ordersResult = await pool.query(
      `SELECT o.id, o.order_number, o.user_id, o.status, o.total_amount,
              o.shipping_address, o.payment_method, o.payment_status,
              o.notes, o.created_at, o.updated_at,
              COUNT(oi.id) AS item_count
       FROM orders o
       LEFT JOIN order_items oi ON o.id = oi.order_id
       ${whereClause}
       GROUP BY o.id
       ORDER BY o.${sortColumn} ${sortOrder}
       LIMIT $${paramIndex++} OFFSET $${paramIndex++}`,
      [...values, limitNum, offset]
    );

    return res.status(200).json({
      success: true,
      data: ordersResult.rows,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages: Math.ceil(total / limitNum),
      },
    } as ApiResponse<Order[]> & { pagination: PaginatedResponse });
  } catch (error) {
    next(error);
  }
});

// ─── GET /:id — Get order details ────────────────────────────────────────────

router.get('/:id', async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = (req as any).user?.sub;
    const userRole = (req as any).user?.role;
    const { id } = req.params;

    const orderResult = await pool.query(
      `SELECT o.id, o.order_number, o.user_id, o.status, o.total_amount,
              o.subtotal, o.tax_amount, o.shipping_amount, o.discount_amount,
              o.shipping_address, o.billing_address, o.payment_method, o.payment_status,
              o.payment_id, o.notes, o.created_at, o.updated_at
       FROM orders o
       WHERE o.id = $1`,
      [id]
    );

    if (orderResult.rows.length === 0) {
      return res.status(404).json({
        success: false,
        error: 'Order not found',
      } as ApiResponse<null>);
    }

    // Non-admin users can only access their own orders
    if (userRole !== 'admin' && orderResult.rows[0].user_id !== userId) {
      return res.status(403).json({
        success: false,
        error: 'Access denied',
      } as ApiResponse<null>);
    }

    // Fetch order items
    const itemsResult = await pool.query(
      `SELECT oi.id, oi.product_id, oi.product_name, oi.product_image,
              oi.unit_price, oi.quantity, oi.subtotal
       FROM order_items oi
       WHERE oi.order_id = $1
       ORDER BY oi.created_at`,
      [id]
    );

    const order = {
      ...orderResult.rows[0],
      items: itemsResult.rows,
    };

    return res.status(200).json({
      success: true,
      data: order,
    } as ApiResponse<typeof order>);
  } catch (error) {
    next(error);
  }
});

// ─── POST / — Create order from cart (checkout) ──────────────────────────────

router.post('/', async (req: Request, res: Response, next: NextFunction) => {
  const client = await pool.connect();

  try {
    const userId = (req as any).user?.sub;
    const {
      shipping_address,
      billing_address,
      payment_method = 'credit_card',
      notes,
    } = req.body;

    if (!shipping_address) {
      return res.status(400).json({
        success: false,
        error: 'Shipping address is required',
      } as ApiResponse<null>);
    }

    // Get user's active cart
    const cartResult = await client.query(
      'SELECT id FROM carts WHERE user_id = $1 AND is_active = TRUE',
      [userId]
    );

    if (cartResult.rows.length === 0) {
      return res.status(400).json({
        success: false,
        error: 'No active cart found. Add items to your cart first.',
      } as ApiResponse<null>);
    }

    const cartId = cartResult.rows[0].id;

    // Validate cart items and check stock
    let validItems: any[];
    try {
      validItems = await validateCartForCheckout(cartId, userId);
    } catch (err: any) {
      return res.status(err.status || 400).json({
        success: false,
        error: err.message,
      } as ApiResponse<null>);
    }

    // Begin transaction
    await client.query('BEGIN');

    // Calculate totals
    const subtotal = validItems.reduce(
      (sum: number, item: any) => sum + parseFloat(item.price) * item.quantity,
      0
    );
    const taxRate = 0.08; // 8% tax rate (configurable)
    const taxAmount = Math.round(subtotal * taxRate * 100) / 100;
    const shippingAmount = subtotal >= 50 ? 0 : 9.99; // Free shipping over $50
    const totalAmount = Math.round((subtotal + taxAmount + shippingAmount) * 100) / 100;

    // Create order
    const orderNumber = generateOrderNumber();
    const orderResult = await client.query(
      `INSERT INTO orders
       (order_number, user_id, status, subtotal, tax_amount, shipping_amount, discount_amount,
        total_amount, shipping_address, billing_address, payment_method, payment_status, notes)
       VALUES ($1, $2, 'pending', $3, $4, $5, $6, $7, $8, $9, $10, 'pending', $11)
       RETURNING *`,
      [
        orderNumber,
        userId,
        subtotal,
        taxAmount,
        shippingAmount,
        0,
        totalAmount,
        JSON.stringify(shipping_address),
        billing_address ? JSON.stringify(billing_address) : null,
        payment_method,
        notes || null,
      ]
    );

    const order = orderResult.rows[0];

    // Create order items and decrement stock
    for (const item of validItems) {
      const itemSubtotal = Math.round(parseFloat(item.price) * item.quantity * 100) / 100;

      await client.query(
        `INSERT INTO order_items (order_id, product_id, product_name, product_image, unit_price, quantity, subtotal)
         VALUES ($1, $2, $3, $4, $5, $6, $7)`,
        [order.id, item.product_id, item.product_name, item.product_image || null, item.price, item.quantity, itemSubtotal]
      );

      // Decrement stock
      await client.query(
        'UPDATE products SET stock_quantity = stock_quantity - $1, updated_at = NOW() WHERE id = $2',
        [item.quantity, item.product_id]
      );
    }

    // Deactivate cart items
    await client.query(
      'UPDATE cart_items SET is_active = FALSE, updated_at = NOW() WHERE cart_id = $1 AND is_active = TRUE',
      [cartId]
    );

    // Deactivate cart
    await client.query(
      'UPDATE carts SET is_active = FALSE, updated_at = NOW() WHERE id = $1',
      [cartId]
    );

    await client.query('COMMIT');

    // Fetch complete order with items
    const itemsResult = await client.query(
      `SELECT oi.id, oi.product_id, oi.product_name, oi.product_image,
              oi.unit_price, oi.quantity, oi.subtotal
       FROM order_items oi
       WHERE oi.order_id = $1
       ORDER BY oi.created_at`,
      [order.id]
    );

    const completeOrder = {
      ...order,
      items: itemsResult.rows,
    };

    return res.status(201).json({
      success: true,
      data: completeOrder,
    } as ApiResponse<typeof completeOrder>);
  } catch (error) {
    await client.query('ROLLBACK');
    next(error);
  } finally {
    client.release();
  }
});

// ─── PUT /:id/status — Update order status (Admin only) ──────────────────────

router.put('/:id/status', requireAdmin, async (req: Request, res: Response, next: NextFunction) => {
  const client = await pool.connect();

  try {
    const { id } = req.params;
    const { status, payment_status, tracking_number } = req.body;

    const validStatuses = ['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled', 'refunded'];
    const validPaymentStatuses = ['pending', 'paid', 'failed', 'refunded'];

    if (status && !validStatuses.includes(status)) {
      return res.status(400).json({
        success: false,
        error: `Invalid status. Must be one of: ${validStatuses.join(', ')}`,
      } as ApiResponse<null>);
    }

    if (payment_status && !validPaymentStatuses.includes(payment_status)) {
      return res.status(400).json({
        success: false,
        error: `Invalid payment status. Must be one of: ${validPaymentStatuses.join(', ')}`,
      } as ApiResponse<null>);
    }

    // Check order exists
    const existingOrder = await client.query('SELECT id, status FROM orders WHERE id = $1', [id]);
    if (existingOrder.rows.length === 0) {
      return res.status(404).json({
        success: false,
        error: 'Order not found',
      } as ApiResponse<null>);
    }

    // Prevent invalid status transitions
    if (status === 'cancelled' && ['shipped', 'delivered'].includes(existingOrder.rows[0].status)) {
      return res.status(400).json({
        success: false,
        error: 'Cannot cancel an order that has already been shipped or delivered',
      } as ApiResponse<null>);
    }

    const updates: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    if (status) {
      updates.push(`status = $${paramIndex++}`);
      values.push(status);
    }

    if (payment_status) {
      updates.push(`payment_status = $${paramIndex++}`);
      values.push(payment_status);
    }

    if (tracking_number !== undefined) {
      updates.push(`tracking_number = $${paramIndex++}`);
      values.push(tracking_number);
    }

    // Handle cancellation: restore stock
    if (status === 'cancelled' && existingOrder.rows[0].status !== 'cancelled') {
      await client.query('BEGIN');

      const items = await client.query(
        'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
        [id]
      );

      for (const item of items.rows) {
        await client.query(
          'UPDATE products SET stock_quantity = stock_quantity + $1, updated_at = NOW() WHERE id = $2',
          [item.quantity, item.product_id]
        );
      }
    }

    if (updates.length === 0) {
      return res.status(400).json({
        success: false,
        error: 'No valid fields to update',
      } as ApiResponse<null>);
    }

    updates.push(`updated_at = NOW()`);
    values.push(id);

    const result = await client.query(
      `UPDATE orders SET ${updates.join(', ')} WHERE id = $${paramIndex}
       RETURNING *`,
      values
    );

    if (status === 'cancelled') {
      await client.query('COMMIT');
    }

    // Fetch items
    const itemsResult = await client.query(
      `SELECT oi.id, oi.product_id, oi.product_name, oi.product_image,
              oi.unit_price, oi.quantity, oi.subtotal
       FROM order_items oi
       WHERE oi.order_id = $1`,
      [id]
    );

    return res.status(200).json({
      success: true,
      data: { ...result.rows[0], items: itemsResult.rows },
    } as ApiResponse<typeof result.rows[0] & { items: any[] }>);
  } catch (error) {
    await client.query('ROLLBACK');
    next(error);
  } finally {
    client.release();
  }
});

// ─── PUT /:id/cancel — Customer cancels their own order ─────────────────────

router.put('/:id/cancel', async (req: Request, res: Response, next: NextFunction) => {
  const client = await pool.connect();

  try {
    const userId = (req as any).user?.sub;
    const { id } = req.params;
    const { reason } = req.body;

    const orderResult = await client.query(
      'SELECT id, user_id, status FROM orders WHERE id = $1',
      [id]
    );

    if (orderResult.rows.length === 0) {
      return res.status(404).json({
        success: false,
        error: 'Order not found',
      } as ApiResponse<null>);
    }

    const order = orderResult.rows[0];

    // Verify ownership or admin
    const userRole = (req as any).user?.role;
    if (order.user_id !== userId && userRole !== 'admin') {
      return res.status(403).json({
        success: false,
        error: 'Access denied',
      } as ApiResponse<null>);
    }

    // Only pending or confirmed orders can be cancelled
    if (!['pending', 'confirmed'].includes(order.status)) {
      return res.status(400).json({
        success: false,
        error: `Cannot cancel an order with status "${order.status}"`,
      } as ApiResponse<null>);
    }

    await client.query('BEGIN');

    // Restore stock
    const items = await client.query(
      'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
      [id]
    );

    for (const item of items.rows) {
      await client.query(
        'UPDATE products SET stock_quantity = stock_quantity + $1, updated_at = NOW() WHERE id = $2',
        [item.quantity, item.product_id]
      );
    }

    // Update order status
    const result = await client.query(
      `UPDATE orders SET status = 'cancelled', notes = COALESCE(notes, '') || $2, updated_at = NOW()
       WHERE id = $1 RETURNING *`,
      [id, reason ? ` | Cancellation reason: ${reason}` : '']
    );

    await client.query('COMMIT');

    const itemsResult = await client.query(
      `SELECT oi.id, oi.product_id, oi.product_name, oi.product_image,
              oi.unit_price, oi.quantity, oi.subtotal
       FROM order_items oi
       WHERE oi.order_id = $1`,
      [id]
    );

    return res.status(200).json({
      success: true,
      data: { ...result.rows[0], items: itemsResult.rows },
    } as ApiResponse<any>);
  } catch (error) {
    await client.query('ROLLBACK');
    next(error);
  } finally {
    client.release();
  }
});

