        cartItems.map((item) =>
          item.product.id === product.id
            ? { ...item, quantity: item.quantity + quantity }
            : item
        )
      );
    } else {
      setCartItems([
        ...cartItems,
        {
          id: `${product.id}-${Date.now()}`,
          product,
          quantity,
          selected: true,
        },
      ]);
    }
    showToast(`已添加 ${product.name} 到购物车`, 'success');
  };

  const removeFromCart = (productId: string) => {
    setCartItems(cartItems.filter((item) => item.product.id !== productId));
  };

  const updateQuantity = (productId: string, quantity: number) => {
    if (quantity <= 0) {
      removeFromCart(productId);
      return;
    }
    setCartItems(
      cartItems.map((item) =>
        item.product.id === productId ? { ...item, quantity } : item
      )
    );
  };

  const toggleSelect = (productId: string) => {
    setCartItems(
      cartItems.map((item) =>
        item.product.id === productId
          ? { ...item, selected: !item.selected }
          : item
      )
    );
  };

  const selectAll = (selected: boolean) => {
    setCartItems(cartItems.map((item) => ({ ...item, selected })));
  };

  const clearCart = () => {
    setCartItems([]);
  };

  // Filter products
  const filteredProducts =
    activeCategory === '全部'
      ? products
      : products.filter((p) => p.category === activeCategory);

  // Toast helper
  const showToast = (message: string, type: 'success' | 'error' | 'info') => {
    setToast({ message, type });
  };

  // User menu handler
  const handleUserClick = () => {
    if (user) {
      // Show user menu or profile
      setAuthTab('login');
      setIsAuthOpen(true);
    } else {
      setAuthTab('login');
      setIsAuthOpen(true);
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated: !!user,
        login,
        register,
        logout,
      }}
    >
      <CartContext.Provider
        value={{
          items: cartItems,
          addToCart,
          removeFromCart,
          updateQuantity,
          toggleSelect,
          selectAll,
          clearCart,
          totalAmount,
          totalItems,
          selectedItems,
        }}
      >
        <div className="app">
          <Header
            onCartClick={() => setIsCartOpen(true)}
            onUserClick={handleUserClick}
            cartItemCount={totalItems}
          />

          <main className="main">
            <HeroSection />

            <div className="container">
              <CategoryPills
                categories={categories}
                activeCategory={activeCategory}
                onSelect={setActiveCategory}
              />

              <FeaturedSection products={products} onAddToCart={addToCart} />

              <ProductsSection products={filteredProducts} onAddToCart={addToCart} />
            </div>
          </main>

          <Footer />

          <CartSidebar isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} />

          <AuthModal
            isOpen={isAuthOpen}
            onClose={() => setIsAuthOpen(false)}
            defaultTab={authTab}
          />

          {toast && (
            <Toast
              message={toast.message}
              type={toast.type}
              onClose={() => setToast(null)}
            />
          )}
        </div>
      </CartContext.Provider>
    </AuthContext.Provider>
  );
};

export default App;

/**
 * API 客户端封装
 * 基于 Axios 的 HTTP 请求处理
 */

import axios, {
  AxiosInstance,
  AxiosError,
  AxiosRequestConfig,
  AxiosResponse,
  InternalAxiosRequestConfig,
} from 'axios';

// ============ Configuration ============

interface ApiClientConfig {
  baseURL: string;
  timeout?: number;
  retryAttempts?: number;
  retryDelay?: number;
}

const defaultConfig: ApiClientConfigConfig = {
  baseURL: import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api',
  timeout: 30000,
  retryAttempts: 3,
  retryDelay: 1000,
};

// ============ Storage Keys ============

const STORAGE_KEYS = {
  ACCESS_TOKEN: 'auth_access_token',
  REFRESH_TOKEN: 'auth_refresh_token',
  USER: 'auth_user',
} as const;

// ============ API Error Types ============

export interface ApiErrorResponse {
  success: false;
  error: string;
  message: string;
  code?: string;
  details?: Record<string, unknown>;
}

export class ApiError extends Error {
  public statusCode: number;
  public code?: string;
  public details?: Record<string, unknown>;
  public isNetworkError: boolean;
  public isTimeout: boolean;

  constructor(
    message: string,
    statusCode: number = 0,
    code?: string,
    details?: Record<string, unknown>
  ) {
    super(message);
    this.name = 'ApiError';
    this.statusCode = statusCode;
    this.code = code;
    this.details = details;
    this.isNetworkError = statusCode === 0;
    this.isTimeout = statusCode === 408;
  }

  static fromAxiosError(error: AxiosError<ApiErrorResponse>): ApiError {
    if (error.code === 'ECONNABORTED') {
      return new ApiError('Request timeout', 408, 'TIMEOUT');
    }

    if (!error.response) {
      return new ApiError(
        error.message || 'Network error',
        0,
        'NETWORK_ERROR'
      );
    }

    const { status, data } = error.response;

    return new ApiError(
      data?.message || data?.error || error.message || 'Unknown error',
      status,
      data?.code,
      data?.details
    );
  }
}

// ============ Token Manager ============

class TokenManager {
  private accessToken: string | null = null;
  private refreshToken: string | null = null;

  constructor() {
    this.loadFromStorage();
  }

  private loadFromStorage(): void {
    try {
      this.accessToken = localStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
      this.refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);
    } catch {
      // localStorage not available
    }
  }

  getAccessToken(): string | null {
    return this.accessToken;
  }

  getRefreshToken(): string | null {
    return this.refreshToken;
  }

  setTokens(accessToken: string, refreshToken: string): void {
    this.accessToken = accessToken;
    this.refreshToken = refreshToken;

    try {
      localStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, accessToken);
      localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, refreshToken);
    } catch {
      // localStorage not available
    }
  }

  clearTokens(): void {
    this.accessToken = null;
    this.refreshToken = null;

    try {
      localStorage.removeItem(STORAGE_KEYS.ACCESS_TOKEN);
      localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN);
      localStorage.removeItem(STORAGE_KEYS.USER);
    } catch {
      // localStorage not available
    }
  }

  isAuthenticated(): boolean {
    return !!this.accessToken;
  }
}

// ============ Request Queue ============

class RequestQueue {
  private queue: Array<() => void> = [];
  private isRefreshing = false;

  async add<T>(request: () => Promise<T>): Promise<T> {
    if (!this.isRefreshing) {
      return request();
    }

    return new Promise((resolve, reject) => {
      this.queue.push(async () => {
        try {
          const result = await request();
          resolve(result);
        } catch (error) {
          reject(error);
        }
      });
    });
  }

  startRefreshing(): void {
    this.isRefreshing = true;
  }

  finishRefreshing(): void {
    this.isRefreshing = false;
    this.queue.forEach((resolve) => resolve());
    this.queue = [];
  }
}

// ============ API Client Class ============

class ApiClient {
  private client: AxiosInstance;
  private tokenManager: TokenManager;
  private requestQueue: RequestQueue;
  private config: ApiClientConfig;

  constructor(config: Partial<ApiClientConfig> = {}) {
    this.config = { ...defaultConfig, ...config };
    this.tokenManager = new TokenManager();
    this.requestQueue = new RequestQueue();

    this.client = this.createClient();
    this.setupInterceptors();
  }

  private createClient(): AxiosInstance {
    return axios.create({
      baseURL: this.config.baseURL,
      timeout: this.config.timeout,
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
    });
  }

  private setupInterceptors(): void {
    // Request Interceptor
    this.client.interceptors.request.use(
      (config: InternalAxiosRequestConfig) => {
        const token = this.tokenManager.getAccessToken();
        if (token && config.headers) {
          config.headers.Authorization = `Bearer ${token}`;
        }

        // Add request timestamp for debugging
        config.metadata = { startTime: new Date() };

        return config;
      },
      (error) => Promise.reject(error)
    );

    // Response Interceptor
    this.client.interceptors.response.use(
      (response: AxiosResponse) => {
        // Log response time in development
        if (import.meta.env.DEV && response.config.metadata?.startTime) {
          const duration = new Date().getTime() - response.config.metadata.startTime.getTime();
          console.debug(`[API] ${response.config.method?.toUpperCase()} ${response.config.url} - ${duration}ms`);
        }
        return response;
      },
      async (error: AxiosError<ApiErrorResponse>) => {
        const originalRequest = error.config as InternalAxiosRequestConfig & { _retry?: boolean };

        // Handle 401 Unauthorized
        if (error.response?.status === 401 && !originalRequest._retry) {
          return this.requestQueue.add(async () => {
            originalRequest._retry = true;

            try {
              const newToken = await this.refreshAccessToken();

              if (newToken && originalRequest.headers) {
                originalRequest.headers.Authorization = `Bearer ${newToken}`;
              }

              return this.client(originalRequest);
            } catch (refreshError) {
              this.tokenManager.clearTokens();
              window.dispatchEvent(new CustomEvent('auth:logout'));
              return Promise.reject(refreshError);
            }
          });
        }

        // Handle network errors with retry
        if (!error.response && this.config.retryAttempts && this.config.retryAttempts > 0) {
          return this.retryRequest(originalRequest);
        }

        return Promise.reject(ApiError.fromAxiosError(error));
      }
    );
  }

  private async refreshAccessToken(): Promise<string | null> {
    const refreshToken = this.tokenManager.getRefreshToken();

    if (!refreshToken) {
      return null;
    }

    this.requestQueue.startRefreshing();

    try {
      const response = await axios.post(`${this.config.baseURL}/auth/refresh`, {
        refreshToken,
      });

      const { accessToken, refreshToken: newRefreshToken } = response.data.data;

      this.tokenManager.setTokens(accessToken, newRefreshToken || accessToken);
      this.requestQueue.finishRefreshing();

      return accessToken;
    } catch {
      this.requestQueue.finishRefreshing();
      return null;
    }
  }

  private async retryRequest(config: InternalAxiosRequestConfig, attempt = 0): Promise<AxiosResponse> {
    const maxAttempts = this.config.retryAttempts || 1;
    const delay = this.config.retryDelay || 1000;

    if (attempt >= maxAttempts) {
      throw ApiError.fromAxiosError(
        new axios.AxiosError('Max retry attempts reached', 'ECONNABORTED')
      );
    }

    await new Promise((resolve) => setTimeout(resolve, delay * Math.pow(2, attempt)));

    try {
      return await this.client(config);
    } catch (error) {
      if (axios.isAxiosError(error) && !error.response) {
        return this.retryRequest(config, attempt + 1);
      }
      throw error;
    }
  }

  // ============ Public Methods ============

  async get<T>(url: string, config?: AxiosRequestConfig): Promise<T> {
    const response = await this.client.get<T>(url, config);
    return response.data;
  }

  async post<T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> {
    const response = await this.client.post<T>(url, data, config);
    return response.data;
  }

  async put<T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> {
    const response = await this.client.put<T>(url, data, config);
    return response.data;
  }

  async patch<T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> {
    const response = await this.client.patch<T>(url, data, config);
    return response.data;
  }

  async delete<T>(url: string, config?: AxiosRequestConfig): Promise<T> {
    const response = await this.client.delete<T>(url, config);
    return response.data;
  }

  async upload<T>(
    url: string,
    formData: FormData,
    onProgress?: (progress: number) => void,
    config?: AxiosRequestConfig
  ): Promise<T> {
    const response = await this.client.post<T>(url, formData, {
      ...config,
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      onUploadProgress: (progressEvent) => {
        if (onProgress && progressEvent.total) {
          const progress = Math.round((progressEvent.loaded * 100) / progressEvent.total);
          onProgress(progress);
        }
      },
    });

    return response.data;
  }

  // ============ Utility Methods ============

  setAuthToken(token: string): void {
    this.tokenManager.setTokens(token, this.tokenManager.getRefreshToken() || token);
  }

  clearAuth(): void {
    this.tokenManager.clearTokens();
  }

  isAuthenticated(): boolean {
    return this.tokenManager.isAuthenticated();
  }

  getAccessToken(): string | null {
    return this.tokenManager.getAccessToken();
  }

  updateConfig(config: Partial<ApiClientConfig>): void {
    this.config = { ...this.config, ...config };
  }
}

// ============ Singleton Instance ============

let apiClientInstance: ApiClient | null = null;

export function getApiClient(config?: Partial<ApiClientConfig>): ApiClient {
  if (!apiClientInstance) {
    apiClientInstance = new ApiClient(config);
  }
  return apiClientInstance;
}

export function createApiClient(config?: Partial<ApiClientConfig>): ApiClient {
  apiClientInstance = new ApiClient(config);
  return apiClientInstance;
}

// ============ Export ============

export default ApiClient;
export { ApiClient, ApiError, type ApiClientConfig, type ApiErrorResponse };

/**
 * 认证 API 接口
 * 处理用户注册、登录、令牌管理等认证相关功能
 */

import { getApiClient, type ApiClient } from './client';
import type {
  ApiResponse,
  User,
  UserProfile,
  AuthResponse,
  LoginRequest,
  RegisterRequest,
  PasswordResetRequest,
  PasswordUpdateRequest,
  RefreshTokenRequest,
} from '../types';

// ============ Auth API Endpoints ============

const AUTH_ENDPOINTS = {
  // Authentication
  LOGIN: '/auth/login',
  REGISTER: '/auth/register',
  LOGOUT: '/auth/logout',
  REFRESH: '/auth/refresh',

  // Password Management
  FORGOT_PASSWORD: '/auth/forgot-password',
  RESET_PASSWORD: '/auth/reset-password',
  CHANGE_PASSWORD: '/auth/change-password',

  // Email Verification
  VERIFY_EMAIL: '/auth/verify-email',
  RESEND_VERIFICATION: '/auth/resend-verification',

  // OAuth
  OAUTH_GOOGLE: '/auth/oauth/google',
  OAUTH_FACEBOOK: '/auth/oauth/facebook',
  OAUTH_GITHUB: '/auth/oauth/github',

  // Social Auth
  LINK_SOCIAL: '/auth/social/link',
  UNLINK_SOCIAL: '/auth/social/unlink',

  // Sessions
  SESSIONS: '/auth/sessions',
  REVOKE_SESSION: '/auth/sessions/:id',
  REVOKE_ALL_SESSIONS: '/auth/sessions/revoke-all',
} as const;

// ============ Auth API Class ============

class AuthApi {
  private client: ApiClient;

  constructor(client?: ApiClient) {
    this.client = client || getApiClient();
  }

  /**
   * 用户登录
   * @param credentials 登录凭证
   * @returns 认证响应包含用户信息和令牌
   */
  async login(credentials: LoginRequest): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.LOGIN,
      credentials
    );
  }

  /**
   * 用户注册
   * @param data 注册信息
   * @returns 认证响应包含用户信息和令牌
   */
  async register(data: RegisterRequest): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.REGISTER,
      data
    );
  }

  /**
   * 用户登出
   * @returns 登出结果
   */
  async logout(): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(AUTH_ENDPOINTS.LOGOUT);
  }

  /**
   * 刷新访问令牌
   * @param data 刷新令牌请求
   * @returns 新的认证响应
   */
  async refreshToken(data: RefreshTokenRequest): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.REFRESH,
      data
    );
  }

  /**
   * 获取当前用户信息
   * @returns 当前登录用户信息
   */
  async getCurrentUser(): Promise<ApiResponse<UserProfile>> {
    return this.client.get<ApiResponse<UserProfile>>('/auth/me');
  }

  /**
   * 更新用户资料
   * @param data 更新的用户资料
   * @returns 更新后的用户信息
   */
  async updateProfile(data: Partial<User>): Promise<ApiResponse<User>> {
    return this.client.patch<ApiResponse<User>>('/auth/me', data);
  }

  /**
   * 上传用户头像
   * @param file 头像文件
   * @param onProgress 上传进度回调
   * @returns 更新后的用户信息
   */
  async uploadAvatar(
    file: File,
    onProgress?: (progress: number) => void
  ): Promise<ApiResponse<User>> {
    const formData = new FormData();
    formData.append('avatar', file);

    return this.client.upload<ApiResponse<User>>(
      '/auth/me/avatar',
      formData,
      onProgress
    );
  }

  /**
   * 请求密码重置
   * @param data 密码重置请求
   * @returns 请求结果
   */
  async forgotPassword(data: PasswordResetRequest): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(
      AUTH_ENDPOINTS.FORGOT_PASSWORD,
      data
    );
  }

  /**
   * 重置密码
   * @param token 重置令牌
   * @param newPassword 新密码
   * @returns 重置结果
   */
  async resetPassword(token: string, newPassword: string): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(
      AUTH_ENDPOINTS.RESET_PASSWORD,
      { token, newPassword }
    );
  }

  /**
   * 修改密码
   * @param data 密码修改请求
   * @returns 修改结果
   */
  async changePassword(data: PasswordUpdateRequest): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(
      AUTH_ENDPOINTS.CHANGE_PASSWORD,
      data
    );
  }

  /**
   * 验证邮箱
   * @param token 验证令牌
   * @returns 验证结果
   */
  async verifyEmail(token: string): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(
      AUTH_ENDPOINTS.VERIFY_EMAIL,
      { token }
    );
  }

  /**
   * 重新发送验证邮件
   * @param email 邮箱地址
   * @returns 发送结果
   */
  async resendVerification(email: string): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(
      AUTH_ENDPOINTS.RESEND_VERIFICATION,
      { email }
    );
  }

  /**
   * Google OAuth 登录
   * @param idToken Google ID Token
   * @returns 认证响应
   */
  async loginWithGoogle(idToken: string): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.OAUTH_GOOGLE,
      { idToken }
    );
  }

  /**
   * Facebook OAuth 登录
   * @param accessToken Facebook Access Token
   * @returns 认证响应
   */
  async loginWithFacebook(accessToken: string): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.OAUTH_FACEBOOK,
      { accessToken }
    );
  }

  /**
   * GitHub OAuth 登录
   * @param code GitHub OAuth Code
   * @returns 认证响应
   */
  async loginWithGithub(code: string): Promise<ApiResponse<AuthResponse>> {
    return this.client.post<ApiResponse<AuthResponse>>(
      AUTH_ENDPOINTS.OAUTH_GITHUB,
      { code }
    );
  }

  /**
   * 获取所有会话
   * @returns 会话列表
   */
  async getSessions(): Promise<ApiResponse<Session[]>> {
    return this.client.get<ApiResponse<Session[]>>(AUTH_ENDPOINTS.SESSIONS);
  }

  /**
   * 撤销指定会话
   * @param sessionId 会话ID
   * @returns 撤销结果
   */
  async revokeSession(sessionId: string): Promise<ApiResponse<null>> {
    const url = AUTH_ENDPOINTS.REVOKE_SESSION.replace(':id', sessionId);
    return this.client.delete<ApiResponse<null>>(url);
  }

  /**
   * 撤销所有其他会话
   * @returns 撤销结果
   */
  async revokeAllSessions(): Promise<ApiResponse<null>> {
    return this.client.post<ApiResponse<null>>(AUTH_ENDPOINTS.REVOKE_ALL_SESSIONS);
  }

  /**
   * 链接社交账号
   * @param provider 提供商
   * @param token 社交账号令牌
   * @returns 链接结果
   */
  async linkSocialAccount(
    provider: 'google' | 'facebook' | 'github',
    token: string
  ): Promise<ApiResponse<User>> {
    return this.client.post<ApiResponse<User>>(
      AUTH_ENDPOINTS.LINK_SOCIAL,
      { provider, token }
    );
  }

  /**
   * 解绑社交账号
   * @param provider 提供商
   * @returns 解绑结果
   */
  async unlinkSocialAccount(provider: 'google' | 'facebook' | 'github'): Promise<ApiResponse<User>> {
    return this.client.delete<ApiResponse<User>>(
      `${AUTH_ENDPOINTS.UNLINK_SOCIAL}/${provider}`
    );
  }
}

