  BRAND: (id: string) => `/brands/${id}`,
  BRAND_SLUG: (slug: string) => `/brands/slug/${slug}`,
  BRAND_PRODUCTS: (id: string) => `/brands/${id}/products`,

  // Reviews
  REVIEWS: (productId: string) => `/products/${productId}/reviews`,
  REVIEW: (productId: string, reviewId: string) => `/products/${productId}/reviews/${reviewId}`,

  // Admin (if needed)
  CREATE: '/products',
  UPDATE: (id: string) => `/products/${id}`,
  DELETE: (id: string) => `/products/${id}`,
} as const;

// ============ Products API Class ============

class ProductsApi {
  private client: ApiClient;

  constructor(client?: ApiClient) {
    this.client = client || getApiClient();
  }

  // ============ Product Listing & Search ============

  /**
   * 获取商品列表
   * @param filter 筛选条件
   * @returns 分页商品列表
   */
  async getProducts(filter?: ProductFilter): Promise<PaginatedResponse<Product>> {
    const params = this.buildFilterParams(filter);

    return this.client.get<PaginatedResponse<Product>>(
      PRODUCTS_ENDPOINTS.LIST,
      { params }
    );
  }

  /**
   * 搜索商品
   * @param query 搜索关键词
   * @param filter 额外筛选条件
   * @returns 搜索结果
   */
  async searchProducts(
    query: string,
    filter?: Omit<ProductFilter, 'search'>
  ): Promise<PaginatedResponse<Product>> {
    const params = {
      q: query,
      ...this.buildFilterParams(filter),
    };

    return this.client.get<PaginatedResponse<Product>>(
      PRODUCTS_ENDPOINTS.SEARCH,
      { params }
    );
  }

  /**
   * 获取精选商品
   * @param limit 返回数量
   * @returns 精选商品列表
   */
  async getFeaturedProducts(limit = 10): Promise<ApiResponse<Product[]>> {
    return this.client.get<ApiResponse<Product[]>>(
      PRODUCTS_ENDPOINTS.FEATURED,
      { params: { limit } }
    );
  }

  /**
   * 获取推荐商品
   * @param productId 当前商品ID
   * @param limit 返回数量
   * @returns 推荐商品列表
   */
  async getRecommendations(
    productId: string,
    limit = 8
  ): Promise<ApiResponse<Product[]>> {
    return this.client.get<ApiResponse<Product[]>>(
      PRODUCTS_ENDPOINTS.RECOMMENDATIONS,
      {
        params: { productId, limit },
      }
    );
  }

  /**
   * 获取商品详情
   * @param id 商品ID
   * @returns 商品详情
   */
  async getProductById(id: string): Promise<ApiResponse<Product>> {
    return this.client.get<ApiResponse<Product>>(
      PRODUCTS_ENDPOINTS.DETAIL(id)
    );
  }

  /**
   * 通过 slug 获取商品
   * @param slug 商品slug
   * @returns 商品详情
   */
  async getProductBySlug(slug: string): Promise<ApiResponse<Product>> {
    return this.client.get<ApiResponse<Product>>(
      PRODUCTS_ENDPOINTS.BY_SLUG(slug)
    );
  }

  /**
   * 获取商品变体列表
   * @param productId 商品ID
   * @returns 变体列表
   */
  async getProductVariants(productId: string): Promise<ApiResponse<ProductVariant[]>> {
    return this.client.get<ApiResponse<ProductVariant[]>>(
      PRODUCTS_ENDPOINTS.VARIANTS(productId)
    );
  }

  /**
   * 获取商品库存状态
   * @param productId 商品ID
   * @param variantId 变体ID（可选）
   * @returns 库存信息
   */
  async getProductInventory(
    productId: string,
    variantId?: string
  ): Promise<ApiResponse<InventoryInfo>> {
    return this.client.get<ApiResponse<InventoryInfo>>(
      PRODUCTS_ENDPOINTS.INVENTORY(productId),
      { params: { variantId } }
    );
  }

  // ============ Related Products ============

  /**
   * 获取相关商品
   * @param productId 商品ID
   * @param limit 返回数量
   * @returns 相关商品列表
   */
  async getRelatedProducts(
    productId: string,
    limit = 8
  ): Promise<ApiResponse<Product[]>> {
    return this.client.get<ApiResponse<Product[]>>(
      PRODUCTS_ENDPOINTS.RELATED(productId),
      { params: { limit } }
    );
  }

  /**
   * 获取常一起购买的商品
   * @param productId 商品ID
   * @param limit 返回数量
   * @returns 常一起购买的商品列表
   */
  async getFrequentlyBoughtTogether(
    productId: string,
    limit = 4
  ): Promise<ApiResponse<Product[]>> {
    return this.client.get<ApiResponse<Product[]>>(
      PRODUCTS_ENDPOINTS.FREQUENTLY_BOUGHT(productId),
      { params: { limit } }
    );
  }

  // ============ Categories ============

  /**
   * 获取所有分类
   * @param includeProducts 是否包含商品数量
   * @returns 分类树
   */
  async getCategories(includeProducts = false): Promise<ApiResponse<CategoryTree[]>> {
    return this.client.get<ApiResponse<CategoryTree[]>>(
      PRODUCTS_ENDPOINTS.CATEGORIES,
      { params: { includeProducts } }
    );
  }

  /**
   * 获取分类详情
   * @param id 分类ID
   * @returns 分类详情
   */
  async getCategoryById(id: string): Promise<ApiResponse<CategoryTree>> {
    return this.client.get<ApiResponse<CategoryTree>>(
      PRODUCTS_ENDPOINTS.CATEGORY(id)
    );
  }

  /**
   * 通过 slug 获取分类
   * @param slug 分类slug
   * @returns 分类详情
   */
  async getCategoryBySlug(slug: string): Promise<ApiResponse<CategoryTree>> {
    return this.client.get<ApiResponse<CategoryTree>>(
      PRODUCTS_ENDPOINTS.CATEGORY_SLUG(slug)
    );
  }

  /**
   * 获取分类下的商品
   * @param categoryId 分类ID
   * @param filter 筛选条件
   * @returns 分页商品列表
   */
  async getCategoryProducts(
    categoryId: string,
    filter?: Omit<ProductFilter, 'category'>
  ): Promise<PaginatedResponse<Product>> {
    const params = this.buildFilterParams(filter);

    return this.client.get<PaginatedResponse<Product>>(
      PRODUCTS_ENDPOINTS.CATEGORY_PRODUCTS(categoryId),
      { params }
    );
  }

  // ============ Brands ============

  /**
   * 获取所有品牌
   * @param includeProducts 是否包含商品数量
   * @returns 品牌列表
   */
  async getBrands(includeProducts = false): Promise<ApiResponse<Brand[]>> {
    return this.client.get<ApiResponse<Brand[]>>(
      PRODUCTS_ENDPOINTS.BRANDS,
      { params: { includeProducts } }
    );
  }

  /**
   * 获取品牌详情
   * @param id 品牌ID
   * @returns 品牌详情
   */
  async getBrandById(id: string): Promise<ApiResponse<Brand>> {
    return this.client.get<ApiResponse<Brand>>(
      PRODUCTS_ENDPOINTS.BRAND(id)
    );
  }

  /**
   * 通过 slug 获取品牌
   * @param slug 品牌slug
   * @returns 品牌详情
   */
  async getBrandBySlug(slug: string): Promise<ApiResponse<Brand>> {
    return this.client.get<ApiResponse<Brand>>(
      PRODUCTS_ENDPOINTS.BRAND_SLUG(slug)
    );
  }

  /**
   * 获取品牌下的商品
   * @param brandId 品牌ID
   * @param filter 筛选条件
   * @returns 分页商品列表
   */
  async getBrandProducts(
    brandId: string,
    filter?: Omit<ProductFilter, 'brand'>
  ): Promise<PaginatedResponse<Product>> {
    const params = this.buildFilterParams(filter);

    return this.client.get<PaginatedResponse<Product>>(
      PRODUCTS_ENDPOINTS.BRAND_PRODUCTS(brandId),
      { params }
    );
  }

  // ============ Reviews ============

  /**
   * 获取商品评价
   * @param productId 商品ID
   * @param options 查询选项
   * @returns 评价列表
   */
  async getProductReviews(
    productId: string,
    options?: {
      page?: number;
      limit?: number;
      rating?: number;
      sort?: 'newest' | 'oldest' | 'highest' | 'lowest' | 'helpful';
    }
  ): Promise<PaginatedResponse<Review>> {
    const params = {
      page: options?.page || 1,
      limit: options?.limit || 10,
      rating: options?.rating,
      sort: options?.sort || 'newest',
    };

    return this.client.get<PaginatedResponse<Review>>(
      PRODUCTS_ENDPOINTS.REVIEWS(productId),
      { params }
    );
  }

  /**
   * 获取商品评分统计
   * @param productId 商品ID
   * @returns 评分统计
   */
  async getProductRatingStats(productId: string): Promise<ApiResponse<RatingStats>> {
    return this.client.get<ApiResponse<RatingStats>>(
      `${PRODUCTS_ENDPOINTS.REVIEWS(productId)}/stats`
    );
  }

  /**
   * 添加商品评价
   * @param productId 商品ID
   * @param data 评价内容
   * @returns 添加的评价
   */
  async addReview(
    productId: string,
    data: ReviewInput
  ): Promise<ApiResponse<Review>> {
    return this.client.post<ApiResponse<Review>>(
      PRODUCTS_ENDPOINTS.REVIEWS(productId),
      data
    );
  }

  /**
   * 更新评价
   * @param productId 商品ID
   * @param reviewId 评价ID
   * @param data 更新内容
   * @returns 更新后的评价
   */
  async updateReview(
    productId: string,
    reviewId: string,
    data: Partial<ReviewInput>
  ): Promise<ApiResponse<Review>> {
    return this.client.patch<ApiResponse<Review>>(
      PRODUCTS_ENDPOINTS.REVIEW(productId, reviewId),
      data
    );
  }

  /**
   * 删除评价
   * @param productId 商品ID
   * @param reviewId 评价ID
   * @returns 删除结果
   */
  async deleteReview(
    productId: string,
    reviewId: string
  ): Promise<ApiResponse<null>> {
    return this.client.delete<ApiResponse<null>>(
      PRODUCTS_ENDPOINTS.REVIEW(productId, reviewId)
    );
  }

  /**
   * 标记评价为有帮助
   * @param productId 商品ID
   * @param reviewId 评价ID
   * @returns 更新后的评价
   */
  async markReviewHelpful(
    productId: string,
    reviewId: string
  ): Promise<ApiResponse<Review>> {
    return this.client.post<ApiResponse<Review>>(
      `${PRODUCTS_ENDPOINTS.REVIEW(productId, reviewId)}/helpful`
    );
  }

  /**
   * 标记评价为无帮助
   * @param productId 商品ID
   * @param reviewId 评价ID
   * @returns 更新后的评价
   */
  async markReviewNotHelpful(
    productId: string,
    reviewId: string
  ): Promise<ApiResponse<Review>> {
    return this.client.post<ApiResponse<Review>>(
      `${PRODUCTS_ENDPOINTS.REVIEW(productId, reviewId)}/not-helpful`
    );
  }

  // ============ Helper Methods ============

  private buildFilterParams(filter?: ProductFilter): Record<string, unknown> {
    if (!filter) return {};

    const params: Record<string, unknown> = {};

    if (filter.category) params.category = filter.category;
    if (filter.subcategory) params.subcategory = filter.subcategory;
    if (filter.brand) params.brand = filter.brand;
    if (filter.minPrice !== undefined) params.minPrice = filter.minPrice;
    if (filter.maxPrice !== undefined) params.maxPrice = filter.maxPrice;
    if (filter.rating !== undefined) params.rating = filter.rating;
    if (filter.inStock !== undefined) params.inStock = filter.inStock;
    if (filter.tags?.length) params.tags = filter.tags.join(',');
    if (filter.sort) params.sort = filter.sort;
    if (filter.page) params.page = filter.page;
    if (filter.limit) params.limit = filter.limit;

    return params;
  }
}

// ============ Additional Types ============

export interface ProductVariant {
  id: string;
  sku: string;
  price: number;
  compareAtPrice?: number;
  quantity: number;
  attributes: Record<string, string>;
  image?: string;
}

export interface InventoryInfo {
  productId: string;
  variantId?: string;
  inStock: boolean;
  quantity: number;
  lowStockThreshold?: number;
  status: 'in_stock' | 'low_stock' | 'out_of_stock' | 'discontinued';
}

export interface CategoryTree extends Category {
  children?: CategoryTree[];
  productCount: number;
}

export interface RatingStats {
  average: number;
  total: number;
  distribution: {
    1: number;
    2: number;
    3: number;
    4: number;
    5: number;
  };
}

export interface ReviewInput {
  rating: number;
  title?: string;
  content: string;
  images?: string[];
}

// ============ Singleton Instance ============

let productsApiInstance: ProductsApi | null = null;

export function getProductsApi(client?: ApiClient): ProductsApi {
  if (!productsApiInstance) {
    productsApiInstance = new ProductsApi(client);
  }
  return productsApiInstance;
}

export function createProductsApi(client?: ApiClient): ProductsApi {
  productsApiInstance = new ProductsApi(client);
  return productsApiInstance;
}

// ============ Export ============

export default ProductsApi;
export { ProductsApi, getProductsApi, createProductsApi };

/**
 * 购物车 API 接口
 * 处理购物车管理、优惠券应用等购物车相关功能
 */

import { getApiClient, type ApiClient } from './client';
import type {
  ApiResponse,
  Cart,
  CartItem,
  AddToCartRequest,
  UpdateCartItemRequest,
  Coupon,
} from '../types';

// ============ Cart API Endpoints ============

const CART_ENDPOINTS = {
  // Cart
  GET: '/cart',
  ADD_ITEM: '/cart/items',
  UPDATE_ITEM: (itemId: string) => `/cart/items/${itemId}`,
  REMOVE_ITEM: (itemId: string) => `/cart/items/${itemId}`,
  CLEAR: '/cart/clear',

  // Cart with Session
  SESSION_CART: '/cart/session',
  MERGE_CART: '/cart/merge',

  // Coupons
  APPLY_COUPON: '/cart/coupon/apply',
  REMOVE_COUPON: '/cart/coupon/remove',
  VALIDATE_COUPON: '/cart/coupon/validate',

  // Shipping
  ESTIMATE_SHIPPING: '/cart/shipping/estimate',
  SET_SHIPPING_METHOD: '/cart/shipping/method',

  // Cart Count
  COUNT: '/cart/count',

  // Wishlist (often related to cart)
  WISHLIST: '/wishlist',
  WISHLIST_ADD: '/wishlist/items',
  WISHLIST_REMOVE: (productId: string) => `/wishlist/items/${productId}`,
  WISHLIST_MOVE_TO_CART: (productId: string) => `/wishlist/items/${productId}/move-to-cart`,
  WISHLIST_CHECK: (productId: string) => `/wishlist/check/${productId}`,
} as const;

// ============ Cart API Class ============

class CartApi {
  private client: ApiClient;

  constructor(client?: ApiClient) {
    this.client = client || getApiClient();
  }

  // ============ Cart Operations ============

  /**
   * 获取当前购物车
   * @returns 购物车信息
   */
  async getCart(): Promise<ApiResponse<Cart>> {
    return this.client.get<ApiResponse<Cart>>(CART_ENDPOINTS.GET);
  }

  /**
   * 添加商品到购物车
   * @param item 商品信息
   * @returns 更新后的购物车
   */
  async addItem(item: AddToCartRequest): Promise<ApiResponse<Cart>> {
    return this.client.post<ApiResponse<Cart>>(CART_ENDPOINTS.ADD_ITEM, item);
  }

  /**
   * 批量添加商品到购物车
   * @param items 商品列表
   * @returns 更新后的购物车
   */
  async addItems(items: AddToCartRequest[]): Promise<ApiResponse<Cart>> {
    return this.client.post<ApiResponse<Cart>>(CART_ENDPOINTS.ADD_ITEM, { items });
  }

  /**
   * 更新购物车商品
   * @param itemId 商品项ID
   * @param data 更新内容
   * @returns 更新后的购物车
   */
  async updateItem(
    itemId: string,
    data: UpdateCartItemRequest
  ): Promise<ApiResponse<Cart>> {
    return this.client.patch<ApiResponse<Cart>>(
      CART_ENDPOINTS.UPDATE_ITEM(itemId),
      data
    );
  }

  /**
   * 移除购物车商品
   * @param itemId 商品项ID
   * @returns 更新后的购物车
   */
  async removeItem(itemId: string): Promise<ApiResponse<Cart>> {
    return this.client.delete<ApiResponse<Cart>>(
      CART_ENDPOINTS.REMOVE_ITEM(itemId)
    );
  }

  /**
   * 清空购物车
   * @returns 清空后的购物车
   */
  async clearCart(): Promise<ApiResponse<Cart>> {
    return this.client.delete<ApiResponse<Cart>>(CART_ENDPOINTS.CLEAR);
  }

  // ============ Session Cart (for non-logged-in users) ============

  /**
   * 获取会话购物车
   * @param sessionId 会话ID
   * @returns 购物车信息
   */
  async getSessionCart(sessionId: string): Promise<ApiResponse<Cart>> {
    return this.client.get<ApiResponse<Cart>>(CART_ENDPOINTS.SESSION_CART, {
      params: { sessionId },
    });
  }

  /**
   * 合并访客购物车到用户购物车
   * @param sessionId 访客会话ID
   * @returns 合并后的购物车
   */
  async mergeCart(sessionId: string): Promise<ApiResponse<Cart>> {
    return this.client.post<ApiResponse<Cart>>(CART_ENDPOINTS.MERGE_CART, {
      sessionId,
    });
  }

  // ============ Coupon Operations ============

  /**
   * 应用优惠券
   * @param code 优惠码
   * @returns 应用后的购物车
   */
  async applyCoupon(code: string): Promise<ApiResponse<Cart>> {
    return this.client.post<ApiResponse<Cart>>(CART_ENDPOINTS.APPLY_COUPON, {
      code,
    });
  }

  /**
   * 移除优惠券
   * @param code 优惠码
   * @returns 更新后的购物车
   */
  async removeCoupon(code: string): Promise<ApiResponse<Cart>> {
    return this.client.delete<ApiResponse<Cart>>(
      CART_ENDPOINTS.REMOVE_COUPON,
      { params: { code } }
    );
  }

  /**
   * 验证优惠券
   * @param code 优惠码
   * @returns 验证结果
   */
  async validateCoupon(code: string): Promise<ApiResponse<CouponValidationResult>> {
    return this.client.post<ApiResponse<CouponValidationResult>>(
      CART_ENDPOINTS.VALIDATE_COUPON,
      { code }
    );
  }

  /**
   * 获取可用的优惠券列表
   * @returns 可用优惠券列表
   */
  async getAvailableCoupons(): Promise<ApiResponse<Coupon[]>> {
    return this.client.get<ApiResponse<Coupon[]>>('/coupons/available');
  }

  // ============ Shipping Operations ============

  /**
   * 估算运费
   * @param address 收货地址
   * @returns 运费选项
   */
  async estimateShipping(address: ShippingAddress): Promise<ApiResponse<ShippingOption[]>> {
    return this.client.post<ApiResponse<ShippingOption[]>>(
      CART_ENDPOINTS.ESTIMATE_SHIPPING,
      address
    );
  }

  /**
   * 设置配送方式
   * @param methodId 配送方式ID
   * @returns 更新后的购物车
   */
  async setShippingMethod(methodId: string): Promise<ApiResponse<Cart>> {
    return this.client.post<ApiResponse<Cart>>(CART_ENDPOINTS.SET_SHIPPING_METHOD, {
      methodId,
    });
  }

  // ============ Cart Count ============

  /**
   * 获取购物车商品数量
   * @returns 商品总数
   */
  async getCartCount(): Promise<ApiResponse<CartCount>> {
    return this.client.get<ApiResponse<CartCount>>(CART_ENDPOINTS.COUNT);
  }

  // ============ Wishlist Operations ============

  /**
   * 获取收藏列表
   * @returns 收藏列表
   */
  async getWishlist(): Promise<ApiResponse<Wishlist>> {
    return this.client.get<ApiResponse<Wishlist>>(CART_ENDPOINTS.WISHLIST);
  }

  /**
   * 添加到收藏
   * @param productId 商品ID
   * @returns 更新后的收藏列表
   */
  async addToWishlist(productId: string): Promise<ApiResponse<Wishlist>> {
    return this.client.post<ApiResponse<Wishlist>>(CART_ENDPOINTS.WISHLIST_ADD, {
      productId,
    });
  }

  /**
   * 从收藏移除
   * @param productId 商品ID
   * @returns 更新后的收藏列表
   */
  async removeFromWishlist(productId: string): Promise<ApiResponse<Wishlist>> {
    return this.client.delete<ApiResponse<Wishlist>>(
      CART_ENDPOINTS.WISHLIST_REMOVE(productId)
    );
  }

  /**
   * 将收藏商品移至购物车
   * @param productId 商品ID
   * @param quantity 数量（可选）
   * @returns 操作结果
   */
  async moveToCart(
    productId: string,
    quantity?: number
  ): Promise<ApiResponse<MoveToCartResult>> {
    return this.client.post<ApiResponse<MoveToCartResult>>(
      CART_ENDPOINTS.WISHLIST_MOVE_TO_CART(productId),
      { quantity }
    );
  }

  /**
   * 检查商品是否在收藏中
   * @param productId 商品ID
   * @returns 检查结果
   */
  async checkWishlist(productId: string): Promise<ApiResponse<WishlistCheck>> {
    return this.client.get<ApiResponse<WishlistCheck>>(
      CART_ENDPOINTS.WISHLIST_CHECK(productId)
    );
  }

  /**
   * 批量添加收藏到购物车
   * @param productIds 商品ID列表
   * @returns 操作结果
   */
  async moveAllToCart(productIds?: string[]): Promise<ApiResponse<MoveAllToCartResult>> {
    return this.client.post<ApiResponse<MoveAllToCartResult>>(
      `${CART_ENDPOINTS.WISHLIST}/move-all-to-cart`,
      { productIds }
    );
  }
}

