import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import type { User } from '../types';
import './Header.css';

interface HeaderProps {
  user?: User | null;
  cartItemCount?: number;
  onLogout?: () => void;
  onSearch?: (query: string) => void;
}

const Header: React.FC<HeaderProps> = ({
  user,
  cartItemCount = 0,
  onLogout,
  onSearch,
}) => {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (onSearch) {
      onSearch(searchQuery);
    } else {
      navigate(`/products?search=${encodeURIComponent(searchQuery)}`);
    }
    setSearchQuery('');
  };

  const handleLogout = () => {
    if (onLogout) {
      onLogout();
    }
    setIsUserMenuOpen(false);
    navigate('/');
  };

  const categories = [
    { name: '电子产品', slug: 'electronics' },
    { name: '服装', slug: 'clothing' },
    { name: '家居用品', slug: 'home' },
    { name: '图书', slug: 'books' },
    { name: '运动户外', slug: 'sports' },
  ];

  return (
    <header className="header">
      <div className="header-container">
        {/* Logo */}
        <Link to="/" className="logo">
          <span className="logo-icon">🛒</span>
          <span className="logo-text">E-Commerce</span>
        </Link>

        {/* Mobile Menu Button */}
        <button
          className="mobile-menu-btn"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          aria-label="Toggle menu"
        >
          <span className={`hamburger ${isMenuOpen ? 'active' : ''}`} />
        </button>

        {/* Navigation */}
        <nav className={`nav ${isMenuOpen ? 'active' : ''}`}>
          {/* Categories Dropdown */}
          <div className="nav-dropdown">
            <button className="nav-link dropdown-toggle">
              <span>📁</span> 商品分类
            </button>
            <div className="dropdown-menu">
              {categories.map((category) => (
                <Link
                  key={category.slug}
                  to={`/products?category=${category.slug}`}
                  className="dropdown-item"
                  onClick={() => setIsMenuOpen(false)}
                >
                  {category.name}
                </Link>
              ))}
            </div>
          </div>

          <Link to="/products" className="nav-link">
            <span>🛍️</span> 全部商品
          </Link>
          <Link to="/deals" className="nav-link">
            <span>🔥</span> 优惠活动
          </Link>
          <Link to="/about" className="nav-link">
            <span>ℹ️</span> 关于我们
          </Link>
        </nav>

        {/* Search Bar */}
        <form className="search-form" onSubmit={handleSearch}>
          <input
            type="text"
            className="search-input"
            placeholder="搜索商品..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button type="submit" className="search-btn" aria-label="Search">
            <span>🔍</span>
          </button>
        </form>

        {/* User Actions */}
        <div className="user-actions">
          {/* Wishlist */}
          <Link to="/wishlist" className="action-btn" aria-label="Wishlist">
            <span>❤️</span>
            <span className="badge">0</span>
          </Link>

          {/* Cart */}
          <Link to="/cart" className="action-btn cart-btn" aria-label="Cart">
            <span>🛒</span>
            {cartItemCount > 0 && (
              <span className="badge cart-badge">{cartItemCount}</span>
            )}
          </Link>

          {/* User Menu */}
          {user ? (
            <div className="user-menu-container">
              <button
                className="user-btn"
                onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
              >
                <span className="user-avatar">
                  {user.avatar ? (
                    <img src={user.avatar} alt={user.name} />
                  ) : (
                    <span>{user.name.charAt(0).toUpperCase()}</span>
                  )}
                </span>
                <span className="user-name">{user.name}</span>
                <span className="dropdown-arrow">▼</span>
              </button>

              {isUserMenuOpen && (
                <div className="user-dropdown">
                  <div className="user-dropdown-header">
                    <p className="user-email">{user.email}</p>
                    <p className="user-role">
                      {user.role === 'admin' ? '管理员' : '会员'}
                    </p>
                  </div>
                  <div className="dropdown-divider" />
                  <Link
                    to="/profile"
                    className="dropdown-item"
                    onClick={() => setIsUserMenuOpen(false)}
                  >
                    <span>👤</span> 个人中心
                  </Link>
                  <Link
                    to="/orders"
                    className="dropdown-item"
                    onClick={() => setIsUserMenuOpen(false)}
                  >
                    <span>📦</span> 我的订单
                  </Link>
                  <Link
                    to="/settings"
                    className="dropdown-item"
                    onClick={() => setIsUserMenuOpen(false)}
                  >
                    <span>⚙️</span> 账户设置
                  </Link>
                  {user.role === 'admin' && (
                    <>
                      <div className="dropdown-divider" />
                      <Link
                        to="/admin"
                        className="dropdown-item"
                        onClick={() => setIsUserMenuOpen(false)}
                      >
                        <span>🔧</span> 管理后台
                      </Link>
                    </>
                  )}
                  <div className="dropdown-divider" />
                  <button className="dropdown-item logout-btn" onClick={handleLogout}>
                    <span>🚪</span> 退出登录
                  </button>
                </div>
              )}
            </div>
          ) : (
            <div className="auth-buttons">
              <Link to="/login" className="btn btn-text">
                登录
              </Link>
              <Link to="/register" className="btn btn-primary">
                注册
              </Link>
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;

